# Example of processing multiple items
@scheduler.task(base=BaseTask, bind=True)
def process_correction_queue(self, **kwargs):
    r = redis.StrictRedis(host=settings.REDIS_HOST, port=6380)

    # Process up to 10 items at a time
    for _ in range(10):
        data = r.lpop('sensors.correct_data')
        if not data:
            break

        sensor_data = json.loads(data)
        correct_data_for_sensor.delay(
            sensor_id=sensor_data['sensor_id'],
            date_begin=sensor_data['date_begin'],
            date_end=sensor_data['date_end']
        )
